solution_code:
#include <iostream>
#include <iomanip>

int main() {
    int n;
    std::cin >> n;
    for (int i = 0; i < n; ++i) {
        int val;
        std::cin >> val;
        std::cout << std::setw(8) << val << "\n";
    }
    return 0;
}

