solution_code:
#include <iostream>
#include <iomanip>

int main() {
    int n;
    std::cin >> n;
    std::cout << std::fixed << std::setprecision(2);
    for (int i = 0; i < n; ++i) {
        double val;
        std::cin >> val;
        std::cout << val << "\n";
    }
    return 0;
}
